```c
#include <stdio.h>

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    int a = 0;
    while (m) {
        a += n / m;
        int temp = m;
        m = n % m;
        n = temp;
    }
    printf("%d", a);
    return 0;
}
```

